function wpbp_first_paragraph_html( string $html ): string {
    $processor = WP_HTML_Processor::create_fragment( $html );
    $capturing = false;
    $depth     = 0;
    $buffer    = '';
    while ( $processor->next_token() ) {
        $type = $processor->get_token_type();
        if ( ! $capturing && 'start tag' === $type && 'p' === $processor->get_tag() ) {
            $capturing = true;
            $depth     = 1;
            $buffer   .= $processor->serialize_token();
            continue;
        }
        if ( ! $capturing ) {
            continue;
        }
        // While capturing, append every token until the matching </p> closes.
        $buffer .= $processor->serialize_token();
        if ( 'start tag' === $type && $processor->get_tag() === 'p' ) {
            $depth++;
        } elseif ( 'end tag' === $type && $processor->get_tag() === 'p' ) {
            $depth--;
            if ( $depth === 0 ) {
                return $buffer;
            }
        }
    }
    return '';
}

function wpbp_strip_scripts( string $html ): string {
    $processor = WP_HTML_Tag_Processor::create_fragment( $html );
    $output    = '';
    while ( $processor->next_tag() ) {
        if ( 'script' === $processor->get_tag() ) {
            $processor->remove_tag();
        }
    }
    return $processor->get_updated_html();
}

function wpbp_replace_script_text( string $html, string $replacement ) {
    $tp = WP_HTML_Tag_Processor::create_fragment( $html );
    if ( ! $tp->next_tag( 'script' ) ) {
        return false;
    }
    if ( ! $tp->set_modifiable_text( $replacement ) ) {
        return false;
    }
    return $tp->get_updated_html();
}

function wpbp_dataset_roundtrip( string $prop ): array {
    $attr = wp_html_custom_data_attribute_name( $prop );
    $back = wp_js_dataset_name( $attr );
    return array( 'attr' => $attr, 'prop' => $back );
}

function wpbp_first_url( string $html ): string {
    $url = get_url_in_content( $html );
    return $url ? $url : '';
}

function wpbp_strip_ie_conditionals( string $html ): string {
    $processor = WP_HTML_Processor::create_fragment( $html );
    $output = '';
    while ( $processor->next_token() ) {
        if ( 'comment' === $processor->get_token_type() && str_starts_with( $processor->get_comment_text(), '[if' ) ) {
            $processor->remove_token();
        }
    }
    return $processor->get_updated_html();
}
